mapper.select:
select s.id, s.school_code, s.school_name, s.category_dict_item_id, d.dict_label as category_label, group_concat(distinct t.tag_name order by t.tag_name separator '、') as tag_summary
and (s.school_code like concat('%', #{keyword}, '%') or s.school_name like concat('%', #{keyword}, '%') or d.dict_label like concat('%', #{keyword}, '%'))
group by s.id, s.school_code, s.school_name, s.category_dict_item_id, d.dict_label order by s.school_name limit #{offset}, #{limit}

mapper.update:
update sys_school
set school_code = #{schoolCode},
    school_name = #{schoolName},
    category_dict_item_id = #{categoryDictItemId}
where id = #{id}

mapper.select:
select count(*)
from sys_school
where category_dict_item_id = #{categoryDictItemId}
